import{_ as r}from"./plugin-vue_export-helper.21dcd24c.js";import{o as t,b as a,ac as c,g as e}from"./framework.4684342f.js";const v='{"title":"2018.05.01 @\u5F70\u5316 \u61F7\u7591\u4EBA\u751F\u9577\u5F81[\u5047\u65E5\u9A0E\u58EB\u65E5\u8A8C]","description":"","frontmatter":{"title":"2018.05.01 @\u5F70\u5316 \u61F7\u7591\u4EBA\u751F\u9577\u5F81[\u5047\u65E5\u9A0E\u58EB\u65E5\u8A8C]","date":"2018-05-01T06:55:26.000Z","categories":["\u5047\u65E5\u9A0E\u58EB\u65E5\u8A8C"]},"headers":[{"level":2,"title":"#\u672C\u9031\u5FC3\u5F97","slug":"\u672C\u9031\u5FC3\u5F97"},{"level":2,"title":"1.\u651C\u8ECA\u888B\u62C6\u524D\u5F8C\u8F2A\uFF0C\u4E0A\u706B\u8ECA\u5F88\u65B9\u4FBF","slug":"_1-\u651C\u8ECA\u888B\u62C6\u524D\u5F8C\u8F2A\uFF0C\u4E0A\u706B\u8ECA\u5F88\u65B9\u4FBF"},{"level":2,"title":"2.\u9A0E\u9577\u9014\u5343\u842C\u4E0D\u8981\u8DDF\u81EA\u5DF1\u904E\u4E0D\u53BB","slug":"_2-\u9A0E\u9577\u9014\u5343\u842C\u4E0D\u8981\u8DDF\u81EA\u5DF1\u904E\u4E0D\u53BB"},{"level":2,"title":"\u4E0B\u96C6\u9810\u544A","slug":"\u4E0B\u96C6\u9810\u544A"}],"relativePath":"Bike/BikeTravel/20180501_\u61F7\u7591\u4EBA\u751F\u9577\u5F81.md","lastUpdated":1679296000872}',i={},s=c('<p><a href="https://www.strava.com/activities/1544701435" target="_blank"><img src="https://farm1.staticflickr.com/910/41144482464_88c558134f.jpg"></a><br><img src="https://farm1.staticflickr.com/956/28006520818_f3df69d2ec_k.jpg" alt=""></p><p>\u9019\u6B21\u539F\u672C\u9810\u8A08\u53BB\u65E5\u6708\u6F6D\uFF0C\u62DC\u8A2A\u670B\u53CB\u9806\u4FBF\u9A0E\u55AE\u8ECA<br> \u4F46\u5C0D\u65B9\u6709\u4E8B\uFF0C\u81E8\u6642\u628A\u884C\u7A0B\u6539\u6210\u8CDE\u6CB9\u6850\u82B1<br> \u4E5F\u7D04\u4E86\u53E6\u4E00\u500B\u96F2\u6797\u670B\u53CB\uFF0C\u4E2D\u5348\u4E00\u8D77\u5403\u98EF<br> \u884C\u7A0B\u5F9E\u5F70\u5316\u8ECA\u7AD9\u51FA\u767C\uFF0C\u6CBF139\u7E23\u9053\u9A0E\u4E0B\u4F86<br> \u4F46\u81EA\u5DF1\u7684\u7C97\u5FC3\u5927\u610F\uFF0C\u6700\u5F8C\u751A\u9EBC\u90FD\u6C92\u770B\u5230<br> \u9019\u6B21\u90FD\u6C92\u60F3\u5230\u8981\u62CD\u7167\uFF0C\u6240\u4EE5\u7167\u7247\u5F88\u5C11<br></p><p>\u524D\u4E00\u665A\u592A\u8208\u596E\uFF0C\u665A\u4E0A\u6C92\u751A\u9EBC\u7761(\u7B2C\u4E00\u6B21\u5E36\u55AE\u8ECA\u4E0A\u706B\u8ECA)<br> \u9694\u5929\u65E9\u4E0A\u5728\u60F3\u600E\u9EBC\u6253\u5305\u88DD\u651C\u8ECA\u888B(\u524D\u4E00\u665A\u6709\u7DF4\u7FD2)<br> \u65E9\u9910\u4E5F\u53EA\u5403\u4E00\u9EDE\u9EDE\uFF0C\u5C31\u8D95\u7DCA\u6536\u62FE\u6771\u897F\u6E96\u5099\u51FA\u767C<br><span style="color:red;">\u65BC\u662F\u5C31\u62B1\u8457\u4EA2\u596E+\u6C92\u7761\u597D+\u6C92\u5403\u98FD\u7684\u72C0\u614B\u51FA\u767C</span><br> \u5230\u53F0\u5357\u706B\u8ECA\u7AD9\u6642\uFF0C\u6709\u8A31\u591A\u5B78\u751F\u51FA\u5165(\u4ECA\u5929\u5B78\u6821\u4ECD\u6709\u4E0A\u8AB2)<br> \u9867\u4E0D\u5F97\u5225\u4EBA\u7684\u773C\u5149\uFF0C\u958B\u59CB\u5C07\u8ECA\u5B50\u5012\u7ACB\u3001\u62C6\u524D\u5F8C\u8F2A\u3001\u88DD\u888B<br> \u524D\u5F8C\u82B1\u4E86\u5C07\u8FD110\u5206\u9418\u5C07\u55AE\u8ECA\u88DD\u5165\u651C\u8ECA\u888B\uFF0C\u63A5\u8457\u9032\u706B\u8ECA\u7AD9<br> \u73FE\u5728\u897F\u90E8\u7DDA\u90FD\u53EF\u4EE5\u7528\u60A0\u904A\u5361\uFF0C\u4E5F\u514D\u53BB\u6392\u968A\u8CB7\u7968\u7684\u6642\u9593<br> \u8D70\u5230\u7B2C12\u7BC0\u8ECA\u5EC2\uFF0C\u524D\u65B9\u4E5F\u6709\u4E09\u500B\u5927\u53D4\u6253\u5305\u55AE\u8ECA\u4E0A\u706B\u8ECA<br> (\u61C9\u8A72\u662F\u5C0F\u647A\uFF0C\u65B0\u71DF\u7AD9\u5C31\u4E0B\u8ECA\uFF0C\u4E0D\u50CF\u662F\u9A0E\u9577\u9014\u7684)</p><p>\u539F\u672C\u9A0E\u5230\u706B\u8ECA\u7AD9\u5168\u8EAB\u6EBC\u900F\uFF0C\u706B\u8ECA\u4E0A\u7684\u51B7\u6C23\u628A\u8863\u670D\u90FD\u5439\u4E7E\u4E86<br> \u751A\u81F3\u5439\u5230\u8EAB\u9AD4\u958B\u59CB\u767C\u6296\uFF0C\u5C31\u8D77\u4F86\u7AD9\u5728\u9760\u7A97\u6709\u592A\u967D\u7684\u5730\u65B9<br> \u6CBF\u8DEF\u7D93\u904E\u96F2\u6797\u3001\u4E8C\u6C34\u3001\u6797\u5167...\uFF0C\u5FC3\u60F3\u7B49\u7B49\u9A0E\u8ECA\u6703\u7D93\u904E\u7684\u5730\u65B9<br> \u60F3\u4E0D\u5230\u6700\u5F8C\u5B8C\u5168\u6C92\u7D93\u904E\u9019\u4E9B\u5730\u65B9\uFF0C\u4EE5\u5F8C\u4E5F\u4E0D\u77E5\u9053\u6709\u6C92\u6709\u6A5F\u6703\u4F86</p><p>\u5230\u5F70\u5316\u706B\u8ECA\u7AD9\u6642\u95938:35\uFF0C\u706B\u8ECA\u6E96\u9EDE\u62B5\u9054\u76EE\u7684\u5730<br> \u4E0B\u8ECA\u5F8C\u958B\u59CB\u7D44\u88DD\u55AE\u8ECA\uFF0C\u9019\u6B21\u6015\u7A81\u767C\u72C0\u6CC1\uFF0C\u4E5F\u5E36\u904B\u52D5\u978B\u5099\u6848<br> \u70BA\u4E86\u6E1B\u5C11\u884C\u674E\u91CD\u91CF\uFF0C\u6C34\u6253\u7B97\u7B2C\u4E00\u7AD9\u518D\u505A\u88DC\u7D66<br> \u63A5\u8FD1\u4E5D\u9EDE\uFF0C\u8ECA\u5B50\u90FD\u88DD\u597D\uFF0C\u4E0A\u597D\u9632\u66EC\uFF0C\u8896\u5957\uFF0C\u6574\u88DD\u4E0A\u8DEF<br> \u7B2C\u4E00\u500B7-11\u88DC\u7D66\u7AD9\u8DDD\u96E25K\uFF0C\u4E5F\u9806\u5229\u88DD\u6EFF\u6C34\uFF0C\u63A5\u7E8C\u4E0B\u500B\u884C\u7A0B</p><p>\u63A5\u8457\u767C\u73FE\u6CBF\u8DEF\u90FD\u662F\u4E0A\u4E0B\u8D77\u4F0F\u7684\u4E18\u9675\u5730\uFF0C\u4E0D\u6642\u9084\u670915%\u7684\u5761<br> \u5F8C\u4F86\u63A5\u53F074\u958B\u59CB\u4E0B\u5761\uFF0C\u4E00\u6642\u8CAA\u6ED1\u932F\u904E\u929C\u63A5139\u7E23\u9053\u7684\u53C9\u8DEF\u53E3<br> \u60F3\u8AAA\u7B49\u4E0B\u500B\u8DEF\u53E3\u518D\u7E5E\u8DEF\u904E\u53BB\uFF0C\u7B49\u8B8A\u66F4\u8DEF\u7DDA\u5F8C\uFF0C\u958B\u59CB\u8FFD<br> \u4ECA\u5929\u8E0F\u983B\u3001\u8F49\u901F\u6574\u500B\u90FD\u4E0A\u4E0D\u4F86\uFF0C\u8FFD\u523010\u9EDE\u534A\u9084\u6C92\u8FFD\u5230\u4EFB\u4F55\u4E00\u500B\u9EDE<br> \u5FC3\u60F3\uFF0C\u9019\u6A23\u4E0B\u53BB\u53EF\u80FD\u9023\u4E2D\u5348\u7684\u98EF\u5C40\u5403\u4E0D\u6210<br><span style="color:red;">\u8A55\u4F30\u4E86\u8EAB\u9AD4\u7684\u72C0\u614B\u3001\u6C23\u6EAB\u3001\u8DEF\u9014\uFF0C\u6C7A\u5B9A\u653E\u68C4\u9019\u6B21\u8DEF\u7DDA<br> \u4ECA\u5929\u53EA\u6709\u5169\u500B\u76EE\u6A19\uFF0C\u7B2C\u4E00\u4E2D\u5348\u8DDF\u670B\u53CB\u5403\u98EF\uFF0C\u7B2C\u4E8C\u9806\u5229\u56DE\u5BB6</span></p><p>\u4E0B\u4E86\u6C7A\u5B9A\u4E0D\u8FFD\u6850\u82B1\u5F8C\uFF0C\u9A0E\u5F97\u6BD4\u8F03\u4E0D\u6703\u90A3\u9EBC\u8D95<br> \u6CBF\u8DEF\u90FD\u662F\u4E00\u7247\u7247\u7684\u7530\uFF0C\u7A2E\u690D\u5404\u7A2E\u690D\u7269(\u6709\u82B1\u3001\u7A3B\u7530\u3001\u843D\u7FBD\u677E...)<br><img src="https://farm1.staticflickr.com/976/40962887965_c8f445c253.jpg" alt=""><br><img src="https://farm1.staticflickr.com/971/40962885965_ce3ec37a9a.jpg" alt=""><br><img src="https://farm1.staticflickr.com/957/41818679922_87fc2c676c.jpg" alt=""><br> \u5F8C\u4F86\u7D93\u904E\u897F\u87BA\u5927\u6A4B\uFF0C\u4E2D\u5348\u9806\u5229\u5230\u96F2\u6797\u8DDF\u670B\u53CB\u5403\u98EF<br><img src="https://farm1.staticflickr.com/912/40962888385_4e104de5da.jpg" alt=""><br> \u670B\u53CB\u5EFA\u8B70\u7B49\u7B49\u53EF\u4EE5\u7E5E\u53BB\u65B0\u6E2F\u901B\u901B\uFF0C\u8CB7\u500B\u4F34\u624B\u79AE(\u65B0\u6E2F\u98F4)</p><p>\u56DE\u7A0B\u5230\u53F0\u5357\u904E\u9E7D\u6C34\uFF0C\u767C\u73FE\u65C1\u908A\u4E5F\u662F\u7A3B\u7530\uFF0C\u4F46\u611F\u89BA\u8DDF\u96F2\u6797\u4E0D\u592A\u4E00\u6A23<br> \u89BA\u5F97\u53F0\u5357\u7684\u4EBA\u53E3\u5BC6\u5EA6\u8F03\u9AD8\uFF0C\u4E5F\u767C\u73FE\u53F0\u5357\u7684\u8DEF\u6CC1\u6BD4\u8F03\u597D<br><img src="https://farm1.staticflickr.com/977/27992898438_5e34fc7337.jpg" alt=""><br><img src="https://farm1.staticflickr.com/906/27992898808_6b7eaed0d4.jpg" alt=""><br><img src="https://farm1.staticflickr.com/981/41861653971_01eac37415.jpg" alt=""><br> \u9019\u6642\u4E5F\u5728\u53CD\u7701\uFF0C\u56DE\u5357\u90E8\u525B\u597D\u6EFF\u4E00\u5E74\u4E86<br> \u60F3\u8457\u60F3\u8457\uFF0C\u4E5F\u8A8D\u6E05\u81EA\u5DF1\u5DF2\u7D93\u4E09\u5341\u591A\u6B72<br> \u9019\u6A23\u9A0E\u8ECA\u611F\u89BA\u4E0D\u662F\u6211\u9019\u5E74\u7D00\u5728\u505A\u7684\u4E8B<br> \u73FE\u5728\u4E0D\u518D\u5E74\u8F15\u6709\u7206\u767C\u529B\uFF0C\u50BE\u5411\u662F\u5065\u5EB7\u904B\u52D5<br> \u9A0E\u77ED\u7A0B\u9084\u597D\uFF0C\u9A0E\u9577\u9014\u7834\u767EK\u53CD\u800C\u662F\u7A2E\u6298\u78E8<br> \u4E4B\u5F8C\u5929\u6C23\u4E5F\u958B\u59CB\u9032\u5165\u590F\u5B63\uFF0C\u4E4B\u5F8C\u6703\u8ABF\u6574\u9A0E\u8ECA\u6BD4\u4F8B</p><h2 id="\u672C\u9031\u5FC3\u5F97" tabindex="-1">#\u672C\u9031\u5FC3\u5F97 <a class="header-anchor" href="#\u672C\u9031\u5FC3\u5F97" aria-hidden="true">#</a></h2><h2 id="_1-\u651C\u8ECA\u888B\u62C6\u524D\u5F8C\u8F2A\uFF0C\u4E0A\u706B\u8ECA\u5F88\u65B9\u4FBF" tabindex="-1">1.\u651C\u8ECA\u888B\u62C6\u524D\u5F8C\u8F2A\uFF0C\u4E0A\u706B\u8ECA\u5F88\u65B9\u4FBF <a class="header-anchor" href="#_1-\u651C\u8ECA\u888B\u62C6\u524D\u5F8C\u8F2A\uFF0C\u4E0A\u706B\u8ECA\u5F88\u65B9\u4FBF" aria-hidden="true">#</a></h2><p>\u9019\u662F\u7B2C\u4E00\u6B21\u7684\u9AD4\u9A57\uFF0C\u88DD\u651C\u8ECA\u5E36\u642D\u706B\u8ECA<br> \u5176\u5BE6\u9019\u500B\u65B9\u5F0F\u53EF\u4EE5\u5230\u706B\u8ECA\u7AD9\u9644\u8FD1\u7684\u9EDE\u65C5\u884C<br> \u9A0E\u4E00\u9A0E\u518D\u6253\u5305\u4E0A\u706B\u8ECA\uFF0C\u611F\u89BA\u53EF\u4EE5\u7528\u9019\u65B9\u5F0F\u74B0\u5CF6!!!</p><h2 id="_2-\u9A0E\u9577\u9014\u5343\u842C\u4E0D\u8981\u8DDF\u81EA\u5DF1\u904E\u4E0D\u53BB" tabindex="-1">2.\u9A0E\u9577\u9014\u5343\u842C\u4E0D\u8981\u8DDF\u81EA\u5DF1\u904E\u4E0D\u53BB <a class="header-anchor" href="#_2-\u9A0E\u9577\u9014\u5343\u842C\u4E0D\u8981\u8DDF\u81EA\u5DF1\u904E\u4E0D\u53BB" aria-hidden="true">#</a></h2><p>\u9019\u6B21\u6C92\u7761\u597D+\u6C92\u5403\u597D\uFF0C\u8EAB\u9AD4\u72C0\u614B\u4E0D\u662F\u597D\u7684\u72C0\u614B<br> \u8EAB\u9AD4\u6C92\u6709\u958B\u6A5F\uFF0C\u8166\u888B\u4E5F\u6C92\u6709\u5F88\u6E05\u695A<br> \u5C0E\u81F4\u9A0E\u8ECA\u90FD\u529B\u4E0D\u5F9E\u5FC3\uFF0C\u5F8C\u534A\u6BB5\u9A0E\u5F97\u5F88\u75DB\u82E6<br> \u4E0B\u6B21\u5982\u679C\u9019\u6A23\uFF0C\u53EF\u80FD\u8981\u8A55\u4F30\u662F\u5426\u653E\u68C4</p><h2 id="\u4E0B\u96C6\u9810\u544A" tabindex="-1">\u4E0B\u96C6\u9810\u544A <a class="header-anchor" href="#\u4E0B\u96C6\u9810\u544A" aria-hidden="true">#</a></h2><p>\u4E94\u6708\u958B\u59CB\u6709\u9032\u5165\u590F\u5B63\u7684\u6C23\u5019<br> \u73FE\u5728\u9023\u8D70\u5728\u8DEF\u4E0A\u90FD\u6703\u958B\u59CB\u5192\u6C57<br> \u4E4B\u5F8C\u53EF\u80FD\u6703\u9A0E\u56FA\u5B9A\u7DF4\u8ECA\u8DEF\u7DDA<br> \u4E5F\u6703\u898F\u5283\u4E00\u4E9B\u77ED\u3001\u4E2D\u7A0B\u7684\u666F\u9EDE<br> \u4E0A\u73ED\u9014\u4E2D\u6CBF\u8DEF\u6709\u4E9B\u963F\u52C3\u52D2\u958B\u4E86<br> \u9019\u5E7E\u5929\u627E\u6642\u9593\u4F86\u62CD</p>',15),l=e("div",{class:"embedly-responsive",style:{position:"relative","padding-bottom":"78.2227%",height:"0",overflow:"hidden"}},[e("iframe",{class:"embedly-embed",frameborder:"0",scrolling:"no",allowfullscreen:"",src:"https://cdn.embedly.com/widgets/media.html?src=https://www.relive.cc/view/vZqNRY2eGqe/widget?r=embed-site&url=https://www.relive.cc/view/vZqNRY2eGqe?r=embed-site&image=https://www.relive.cc/view/vZqNRY2eGqe/png?x-ref=embed-site&key=f1631a41cb254ca5b035dc5747a5bd75&type=text/html&schema=relive",width:"1024",height:"801",style:{position:"absolute",top:"0",left:"0",width:"100%",height:"100%"}})],-1),b=[s,l];function p(d,o,h,_,m,f){return t(),a("div",null,b)}var w=r(i,[["render",p]]);export{v as __pageData,w as default};
